465	// BuildArgs constructs the argument array for a harness invocation.
466	// Exported for testing.
467	func BuildArgs(h harnessConfig, in buildArgsInput, model string) []string {
468		// Use BaseArgs if set, fall back to legacy Args for compatibility.
469		base := h.BaseArgs
470		if base == nil {
471			base = h.Args
472		}
473		args := append([]string{}, base...)
474	
475		// Append permission-specific args.
476		if h.PermissionArgs != nil {
477			level := in.Permissions
478			if level == "" {
479				level = "safe"
480			}
481			if extra, ok := h.PermissionArgs[level]; ok {
482				args = append(args, extra...)
483			}
484		}
485	
486		if in.WorkDir != "" && h.WorkDirFlag != "" {
487			args = append(args, h.WorkDirFlag, in.WorkDir)
488		}
489		if model != "" && h.ModelFlag != "" {
490			args = append(args, h.ModelFlag, model)
491		}
492		if in.Effort != "" && h.EffortFlag != "" {
493			if h.EffortFormat != "" {
494				args = append(args, h.EffortFlag, fmt.Sprintf(h.EffortFormat, in.Effort))
495			} else {
496				args = append(args, h.EffortFlag, in.Effort)
497			}
498		}
499		if h.PromptMode == "arg" {
500			args = append(args, in.Prompt)
501		}
502		return args
503	}
