505	// processResult converts execution output to a Result.
506	func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
507		result := &Result{
508			Harness:    harnessName,
509			Model:      model,
510			DurationMS: int(elapsed.Milliseconds()),
511		}
512	
513		if execResult != nil {
514			result.Output = execResult.Stdout
515			result.Stderr = execResult.Stderr
516			result.ExitCode = execResult.ExitCode
517		}
518	
519		if execResult != nil && execResult.EarlyCancel {
520			result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
521			result.ExitCode = -1
522		} else if execResult != nil && execResult.WallClockTimeout {
523			// Wall-clock cap fired regardless of stream activity; distinguish
524			// this from the resettable idle timer so operators can tell the two
525			// failure modes apart in result.json and session logs.
526			reportedElapsed := execResult.WallClockElapsed
527			if reportedElapsed == 0 {
528				reportedElapsed = elapsed
529			}
530			result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
531			result.ExitCode = -1
532		} else if execErr != nil {
533			if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
534				result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
535				result.ExitCode = -1
536			} else {
537				result.Error = execErr.Error()
538				if result.ExitCode == 0 {
539					result.ExitCode = -1
540				}
541			}
542		} else if execResult != nil && execResult.ExitCode != 0 {
543			result.Error = execResult.Stderr
544		}
545	
546		result.Tokens = ExtractTokens(result.Output, harness)
547		usage := ExtractUsage(harnessName, result.Output)
548		result.InputTokens = usage.InputTokens
549		result.OutputTokens = usage.OutputTokens
550		result.CostUSD = usage.CostUSD
551		return result
552	}
