561	// ExtractUsage parses structured token usage from agent output.
562	// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
563	// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
564	// Returns zero-value UsageData if parsing fails or the harness is unsupported.
565	func ExtractUsage(harnessName string, output string) UsageData {
566		switch harnessName {
567		case "codex":
568			for _, line := range strings.Split(output, "\n") {
569				line = strings.TrimSpace(line)
570				if line == "" || !strings.Contains(line, `"turn.completed"`) {
571					continue
572				}
573				var event struct {
574					Type  string `json:"type"`
575					Usage struct {
576						InputTokens  int `json:"input_tokens"`
577						OutputTokens int `json:"output_tokens"`
578					} `json:"usage"`
579				}
580				if err := json.Unmarshal([]byte(line), &event); err != nil {
581					continue
582				}
583				if event.Type == "turn.completed" {
584					return UsageData{
585						InputTokens:  event.Usage.InputTokens,
586						OutputTokens: event.Usage.OutputTokens,
587					}
588				}
589			}
590			return UsageData{}
591		case "claude":
592			// Claude may emit either the legacy single-JSON envelope
593			// ({"usage":{...},"total_cost_usd":N,"result":"..."}) or a stream-json
594			// sequence of one JSON event per line, the last of which is a
595			// {"type":"result",...} event with the same usage/cost fields.
596			return extractUsageClaude(output)
597		case "opencode":
598			// opencode -f json emits a JSON object; parse usage fields if present.
599			var envelope struct {
600				Usage struct {
601					InputTokens  int `json:"input_tokens"`
602					OutputTokens int `json:"output_tokens"`
603				} `json:"usage"`
604				TotalCostUSD float64 `json:"total_cost_usd"`
605			}
606			if err := json.Unmarshal([]byte(output), &envelope); err != nil {
607				// Try last non-empty line (in case of preamble).
608				lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
609				last := ""
610				for i := len(lines) - 1; i >= 0; i-- {
611					if strings.TrimSpace(lines[i]) != "" {
612						last = lines[i]
613						break
614					}
615				}
616				if last == "" {
617					return UsageData{}
618				}
619				if err2 := json.Unmarshal([]byte(last), &envelope); err2 != nil {
620					return UsageData{}
621				}
622			}
623			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
624				return UsageData{}
625			}
626			return UsageData{
627				InputTokens:  envelope.Usage.InputTokens,
628				OutputTokens: envelope.Usage.OutputTokens,
629				CostUSD:      envelope.TotalCostUSD,
630			}
631		case "pi":
632			// pi outputs JSONL - cost is in intermediate events, summary at end has no cost
633			// Scan backwards to find the last line with cost data
634			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
635			var inputTokens, outputTokens int
636			var costUSD float64
637			for i := len(lines) - 1; i >= 0; i-- {
638				line := strings.TrimSpace(lines[i])
639				if line == "" {
640					continue
641				}
642				// Try to parse as pi event with usage/cost
643				// Format: {"type":"text_end","message":{"usage":{"input":N,"output":M,"cost":{"total":X}}}}
644				var event struct {
645					Type    string `json:"type"`
646					Message struct {
647						Usage struct {
648							Input  int `json:"input"`
649							Output int `json:"output"`
650							Cost   struct {
651								Total float64 `json:"total"`
652							} `json:"cost"`
653						} `json:"usage"`
654					} `json:"message"`
655					Partial struct {
656						Usage struct {
657							Input  int `json:"input"`
658							Output int `json:"output"`
659							Cost   struct {
660								Total float64 `json:"total"`
661							} `json:"cost"`
662						} `json:"usage"`
663					} `json:"partial"`
664				}
665				if err := json.Unmarshal([]byte(line), &event); err != nil {
666					continue
667				}
668				// Check message.usage first, then partial.usage
669				if event.Message.Usage.Input > 0 || event.Message.Usage.Output > 0 {
670					inputTokens = event.Message.Usage.Input
671					outputTokens = event.Message.Usage.Output
672					costUSD = event.Message.Usage.Cost.Total
673					break
674				}
675				if event.Partial.Usage.Input > 0 || event.Partial.Usage.Output > 0 {
676					inputTokens = event.Partial.Usage.Input
677					outputTokens = event.Partial.Usage.Output
678					costUSD = event.Partial.Usage.Cost.Total
679					break
680				}
681			}
682			return UsageData{
683				InputTokens:  inputTokens,
684				OutputTokens: outputTokens,
685				CostUSD:      costUSD,
686			}
687		case "gemini":
688			// gemini outputs single JSON with stats.models[].tokens (no cost in JSON)
689			lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
690			last := ""
691			for i := len(lines) - 1; i >= 0; i-- {
692				if strings.TrimSpace(lines[i]) != "" {
693					last = lines[i]
694					break
695				}
696			}
697			if last == "" {
698				return UsageData{}
699			}
700			var envelope struct {
701				Stats struct {
702					Models map[string]struct {
703						Tokens struct {
704							Input int `json:"input"`
705							Total int `json:"total"`
706						} `json:"tokens"`
707					} `json:"models"`
708				} `json:"stats"`
709			}
710			if err := json.Unmarshal([]byte(last), &envelope); err != nil {
711				return UsageData{}
712			}
713			inputTokens := 0
714			outputTokens := 0
715			for _, model := range envelope.Stats.Models {
716				inputTokens += model.Tokens.Input
717				outputTokens += model.Tokens.Total - model.Tokens.Input
718			}
719			// Gemini JSON output doesn't include cost
720			return UsageData{
721				InputTokens:  inputTokens,
722				OutputTokens: outputTokens,
723				CostUSD:      0,
724			}
725		default:
726			return UsageData{}
727		}
728	}
