730	// ExtractOutput extracts clean text from raw agent output based on harness format.
731	// For codex: scans JSONL for type=item.completed with item.type=agent_message, returns item.text
732	// For claude: parses JSON envelope and returns the 'result' field
733	// For agent/opencode: returns output as-is (no transformation needed)
734	// For unknown harnesses or malformed input: returns output as-is
735	func ExtractOutput(harnessName string, rawOutput string) string {
736		switch harnessName {
737		case "codex":
738			return extractOutputCodex(rawOutput)
739		case "claude":
740			return extractOutputClaude(rawOutput)
741		case "agent", "opencode":
742			// agent and opencode return clean text directly
743			return rawOutput
744		case "pi", "gemini":
745			return extractOutputPiGemini(rawOutput)
746		default:
747			// Unknown harnesses return output as-is
748			return rawOutput
749		}
750	}
751	
752	func extractOutputPiGemini(rawOutput string) string {
753		// pi outputs JSONL (last line has summary), gemini outputs single JSON
754		// Try to parse the last non-empty line for the response field
755		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
756		last := ""
757		for i := len(lines) - 1; i >= 0; i-- {
758			if strings.TrimSpace(lines[i]) != "" {
759				last = lines[i]
760				break
761			}
762		}
763		if last == "" {
764			return rawOutput
765		}
766		var envelope struct {
767			Response string `json:"response"`
768		}
769		if err := json.Unmarshal([]byte(last), &envelope); err != nil {
770			return rawOutput
771		}
772		return envelope.Response
773	}
774	
775	func extractOutputCodex(rawOutput string) string {
776		for _, line := range strings.Split(rawOutput, "\n") {
777			line = strings.TrimSpace(line)
778			if line == "" {
779				continue
780			}
781			var item struct {
782				Type string `json:"type"`
783				Item struct {
784					Type string `json:"type"`
785					Text string `json:"text"`
786				} `json:"item"`
787			}
788			if err := json.Unmarshal([]byte(line), &item); err != nil {
789				continue
790			}
791			if item.Type == "output" && item.Item.Type == "agent_message" {
792				return item.Item.Text
793			}
794		}
795		return rawOutput
796	}
