798	func extractOutputClaude(rawOutput string) string {
799		// Legacy non-streaming mode: single JSON envelope with a "result" field.
800		var envelope struct {
801			Result string `json:"result"`
802		}
803		if err := json.Unmarshal([]byte(rawOutput), &envelope); err == nil && envelope.Result != "" {
804			return envelope.Result
805		}
806		// Stream-json mode: scan lines for the final {"type":"result",...} event.
807		lines := strings.Split(strings.TrimRight(rawOutput, "\n"), "\n")
808		for i := len(lines) - 1; i >= 0; i-- {
809			line := strings.TrimSpace(lines[i])
810			if line == "" {
811				continue
812			}
813			var ev struct {
814				Type   string `json:"type"`
815				Result string `json:"result"`
816			}
817			if err := json.Unmarshal([]byte(line), &ev); err == nil {
818				if ev.Type == "result" && ev.Result != "" {
819					return ev.Result
820				}
821				if ev.Type == "" && ev.Result != "" {
822					// Legacy envelope as last line.
823					return ev.Result
824				}
825			}
826		}
827		return rawOutput
828	}
