830	// extractUsageClaude parses token usage and cost from claude output.
831	// It handles both the legacy non-streaming envelope and the stream-json
832	// format (one JSON event per line, final "result" event carries usage).
833	func extractUsageClaude(output string) UsageData {
834		parse := func(s string) (UsageData, bool) {
835			var envelope struct {
836				Type  string `json:"type"`
837				Usage struct {
838					InputTokens  int `json:"input_tokens"`
839					OutputTokens int `json:"output_tokens"`
840				} `json:"usage"`
841				TotalCostUSD float64 `json:"total_cost_usd"`
842			}
843			if err := json.Unmarshal([]byte(s), &envelope); err != nil {
844				return UsageData{}, false
845			}
846			if envelope.Usage.InputTokens == 0 && envelope.Usage.OutputTokens == 0 && envelope.TotalCostUSD == 0 {
847				return UsageData{}, false
848			}
849			return UsageData{
850				InputTokens:  envelope.Usage.InputTokens,
851				OutputTokens: envelope.Usage.OutputTokens,
852				CostUSD:      envelope.TotalCostUSD,
853			}, true
854		}
855	
856		// Try whole output as a single JSON envelope first (legacy path).
857		if u, ok := parse(output); ok {
858			return u
859		}
860		// Stream-json: scan lines, prefer the final "type":"result" event,
861		// else fall back to the last line that parses with usage.
862		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
863		for i := len(lines) - 1; i >= 0; i-- {
864			line := strings.TrimSpace(lines[i])
865			if line == "" {
866				continue
867			}
868			if u, ok := parse(line); ok {
869				return u
870			}
871		}
872		return UsageData{}
873	}
