875	// ExtractTokens parses token usage from agent output using the harness's pattern.
876	// For codex, it delegates to ExtractUsage and returns total tokens (input + output).
877	func ExtractTokens(output string, harness harnessConfig) int {
878		if harness.Name == "codex" {
879			usage := ExtractUsage("codex", output)
880			if usage.InputTokens > 0 || usage.OutputTokens > 0 {
881				return usage.InputTokens + usage.OutputTokens
882			}
883		}
884		if harness.TokenPattern == "" {
885			return 0
886		}
887		re, err := regexp.Compile(harness.TokenPattern)
888		if err != nil {
889			return 0
890		}
891		matches := re.FindStringSubmatch(output)
892		if len(matches) > 1 {
893			cleaned := strings.ReplaceAll(matches[1], ",", "")
894			n, _ := strconv.Atoi(cleaned)
895			return n
896		}
897		return 0
898	}
