968	// TestProviderConnectivity sends a lightweight probe to check if the provider is reachable and has credits.
969	// Returns ProviderStatus with connectivity information.
970	func (r *Runner) TestProviderConnectivity(harnessName string, timeout time.Duration) ProviderStatus {
971		status := ProviderStatus{Reachable: false}
972	
973		// Skip embedded harnesses - they don't have external providers
974		if harnessName == "virtual" || harnessName == "agent" {
975			status.Reachable = true
976			status.CreditsOK = true
977			return status
978		}
979	
980		harness, ok := r.registry.Get(harnessName)
981		if !ok {
982			status.Error = "unknown harness"
983			return status
984		}
985	
986		// Check if binary exists first
987		if harnessName != "virtual" && harnessName != "agent" {
988			if _, err := r.LookPath(harness.Binary); err != nil {
989				status.Error = "binary not found"
990				return status
991			}
992		}
993	
994		// Send a lightweight probe request to test connectivity
995		probePrompt := "echo ok"
996		opts := RunOptions{
997			Harness: harnessName,
998			Prompt:  probePrompt,
999			Timeout: timeout,
1000		}
1001	
1002		start := time.Now()
1003		result, err := r.Run(opts)
1004		duration := time.Since(start)
1005	
1006		if err != nil {
1007			status.Error = fmt.Sprintf("probe failed: %v (%.0fs)", err, duration.Seconds())
1008			// Check for common error patterns indicating credit/quota issues
1009			errStr := strings.ToLower(err.Error())
1010			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
1011				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
1012				status.CreditsOK = false
1013			}
1014			return status
1015		}
1016	
1017		// Check exit code and error from result
1018		if result.ExitCode != 0 || result.Error != "" {
1019			errStr := strings.ToLower(result.Error)
1020			status.Error = fmt.Sprintf("probe failed: %s (%.0fs)", result.Error, duration.Seconds())
1021			// Check for credit/quota errors
1022			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
1023				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
1024				status.CreditsOK = false
1025			}
1026			return status
1027		}
1028	
1029		// Probe succeeded
1030		status.Reachable = true
1031		status.CreditsOK = true
1032		return status
1033	}
